package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.IOException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Iterator;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private Method expectMethod;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a minimal JsonElement to instantiate JsonTreeReader
        JsonElement element = new JsonNull();

        jsonTreeReader = new JsonTreeReader(element);

        // Access private expect method via reflection
        expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);
    }

    @Test
    public void expect_whenTokenMatches_doesNotThrow() throws Exception {
        // Arrange
        // We need to mock peek() to return the expected token.
        // Since peek() is public, override it with a spy.
        JsonTreeReader spyReader = spy(jsonTreeReader);
        JsonToken expected = JsonToken.NULL;
        doReturn(expected).when(spyReader).peek();

        // Act & Assert
        expectMethod.invoke(spyReader, expected);
    }

    @Test
    public void expect_whenTokenDoesNotMatch_throwsIllegalStateException() throws Exception {
        // Arrange
        JsonToken expected = JsonToken.BEGIN_OBJECT;
        JsonToken actual = JsonToken.END_ARRAY;

        // Create a spy on the original jsonTreeReader
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Mock peek() to return the actual token (mismatch)
        doReturn(actual).when(spyReader).peek();

        // Use reflection to override locationString() by setting accessible and invoking a helper
        // Since locationString() is private and final class cannot be subclassed,
        // we use a spy with Mockito's doReturn for a private method via reflection hack.

        // Unfortunately, Mockito cannot mock private methods directly.
        // So we use reflection to access the method and then use a wrapper method to call expect with a patched locationString.

        // We create a helper class with a public method that calls expect and overrides locationString temporarily via reflection.

        class JsonTreeReaderHelper {
            private final JsonTreeReader reader;

            JsonTreeReaderHelper(JsonTreeReader reader) {
                this.reader = reader;
            }

            // Use reflection to temporarily replace the locationString method by a proxy
            String locationString() {
                return " at path $";
            }

            void callExpect(JsonToken expected) throws Exception {
                // Use reflection to invoke expect
                Method expect = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
                expect.setAccessible(true);

                // Because expect internally calls locationString(), and we cannot override it,
                // we use Mockito spy to mock locationString() via a workaround:

                // Create a spy of the reader
                JsonTreeReader spy = spy(reader);

                // Use reflection to get locationString method
                Method locationStringMethod = JsonTreeReader.class.getDeclaredMethod("locationString");
                locationStringMethod.setAccessible(true);

                // Use Mockito to mock locationString() by using doAnswer on the spy
                doAnswer(invocation -> " at path $").when(spy).getClass()
                        .getDeclaredMethod("locationString")
                        .invoke(spy);

                // However, above won't work because Mockito can't mock private methods directly.

                // So instead, we use reflection to invoke expect on the spy, and patch locationString() by temporarily changing the method via reflection is impossible.

                // Therefore, we create a subclass of JsonTreeReaderHelper that overrides locationString and calls expect on the original reader.

                // Instead, just invoke expect on the spyReader and catch the exception, then verify message contains " at path $"

                // But since locationString() cannot be mocked, we can cheat by using a spyReader and set the path field to make locationString() return " at path $"

                // So we will just invoke expect on spyReader and catch exception, then verify message contains expected text.

                try {
                    expect.invoke(spy, expected);
                    fail("Expected IllegalStateException");
                } catch (java.lang.reflect.InvocationTargetException e) {
                    Throwable cause = e.getCause();
                    assertNotNull(cause);
                    assertTrue(cause instanceof IllegalStateException);
                    // Because locationString() is not mocked, message will have default path.
                    // So just check the prefix.
                    String message = cause.getMessage();
                    assertTrue(message.startsWith("Expected " + expected + " but was " + actual));
                }
            }
        }

        // Since the above helper cannot mock locationString(), we simplify test to just verify exception thrown.

        // Act & Assert
        IllegalStateException thrown = assertThrows(IllegalStateException.class,
                () -> expectMethod.invoke(spyReader, expected));

        Throwable cause = thrown.getCause();
        assertNotNull(cause);
        assertTrue(cause instanceof IllegalStateException);
        assertEquals("Expected " + expected + " but was " + actual + spyReader.getPath(), cause.getMessage());
    }
}
